INSERT INTO DQ_FRAMEWORK.METADATA.DQ_EXPECTATION_MASTER (EXPECTATION_ID, VALIDATION_NAME, DESCRIPTION, DIMENSION, IS_ACTIVE, CHECK_TYPE, SUB_DIMENSION, INSTRUCTION_TEXT, DQ_ENGINE, EXPECTED_DATATYPE, CHECK_LEVEL) VALUES
    (1, 'expect_column_values_to_be_null', 'Expect the column values to be null.', 'COMPLETENESS', 'Y', 'NULL_CHECK', 'Completeness', 'Please provide the column name and      optionally a value for "mostly" (a float between 0 and 1) to specify the fraction of values expected to be null.', 'SQL', 'ALL', 'ROW'),
    (2, 'expect_column_values_to_not_be_null', 'Expect the column values to not be null', 'COMPLETENESS', 'Y', 'NOT_NULL_CHECK', 'Completeness', 'Provide column name to check non-nulls. Example: cancellation_reason', 'SQL', 'ALL', 'ROW'),
    (3, 'expect_table_row_count_to_be_between', 'Expect the number of rows to be between two values', 'VOLUME', 'Y', 'ROW_COUNT_RANGE', 'Row Count Range', 'Provide min and max row count. Example: 1000, 100000', 'SQL', NULL, 'TABLE'),
    (4, 'expect_table_row_count_to_equal_other_table', 'Expect the number of rows to equal the number in another table within the same database', 'VOLUME', 'Y', 'ROW_COUNT_MATCH', 'Row Count Match', 'Provide table name whose row count should match. Example: customer_dim', 'SQL', NULL, 'TABLE'),
    (5, 'expect_column_values_to_be_recent', 'Expect date column to have values within the last 24 hours for freshness validation.', 'FRESHNESS', 'Y', 'FRESHNESS_CHECK', 'Freshness Check', 'Provide the column name, freshness threshold amount (integer), threshold unit (e.g., ''hours'', ''minutes''), and optionally the timezone.      Example: last_update_date, 24, hours, UTC', 'SQL', 'TIMESTAMP_LTZ, TIMESTAMP_NTZ', 'TABLE'),
    (6, 'expect_column_to_exist', 'Checks for the existence of a specified column within a table.', 'SCHEMA', 'Y', 'COLUMN_EXISTS', 'Column Structure', 'Provide the column name that must exist. Example: user_id', 'SQL', NULL, 'SCHEMA'),
    (7, 'expect_column_values_to_be_of_type', 'Expect a column to contain values of a specified data type', 'SCHEMA', 'Y', 'DATA_TYPE_CHECK', 'Data Type Check', 'Please provide the column which needs to be checked and datatype also in type_. Example: user_id,int', 'SQL', 'ALL', 'SCHEMA'),
    (8, 'expect_table_column_count_to_be_between', 'Expect the number of columns in a table to be between two values', 'SCHEMA', 'Y', 'COLUMN_COUNT_RANGE', 'Column Structure', 'Provide minimum and maximum expected number of columns. Example: 5, 10', 'SQL', NULL, 'SCHEMA'),
    (9, 'expect_table_columns_to_match_set', 'Expect the columns in a table to match an unordered set', 'SCHEMA', 'Y', 'COLUMN_SET_MATCH', 'Column Structure', 'Provide list of expected columns. Example: ["id", "name", "age"]', 'SQL', NULL, 'SCHEMA'),
    (10, 'expect_column_values_to_be_between', 'Expect the column entries to be between a minimum value and a maximum value (inclusive)', 'NUMERIC', 'Y', 'RANGE_CHECK', 'Range Check', 'Provide maximum and minimum value which needs to be checked for a given column. Example: 100,0', 'SQL', 'NUMBER, FLOAT', 'ROW'),
    (11, 'expect_column_max_to_be_between', 'Expect the column maximum to be between a minimum value and a maximum value', 'NUMERIC', 'Y', 'MAX_RANGE_CHECK', 'Range Check', 'Provide minimum and maximum value which needs to be checked for a given column. Example: 0,100', 'SQL', 'NUMBER, FLOAT', 'AGGREGATE'),
    (12, 'expect_column_mean_to_be_between', 'Expect the column mean to be between a minimum value and a maximum value (inclusive)', 'NUMERIC', 'Y', 'MEAN_RANGE_CHECK', 'Statistical Check', 'Provide minimum and maximum values to validate against column mean. Example: 10.5, 50.0', 'SQL', 'NUMBER, FLOAT', 'AGGREGATE'),
    (13, 'expect_column_median_to_be_between', 'Expect the column median to be between a minimum value and a maximum value.', 'NUMERIC', 'Y', 'MEDIAN_RANGE_CHECK', 'Statistical Check', 'Provide minimum and maximum values to validate against column median. Example: 10, 100', 'SQL', 'NUMBER, FLOAT', 'AGGREGATE'),
    (14, 'expect_column_min_to_be_between', 'Expect the column minimum to be between a minimum value and a maximum value.', 'NUMERIC', 'Y', 'MIN_RANGE_CHECK', 'Range Check', 'Provide minimum and maximum value which needs to be checked for a given column. Example: 0,100', 'SQL', 'NUMBER, FLOAT', 'AGGREGATE'),
    (15, 'expect_column_pair_values_a_to_be_greater_than_b', 'Expect the values in column A to be greater than column B', 'NUMERIC', 'Y', 'COL_PAIR_COMPARE', 'Column Pair Range', 'Provide column A and column B to check A > B. Example: selling_price,cost_price', 'SQL', 'NUMBER, FLOAT', 'ROW'),
    (16, 'expect_column_stdev_to_be_between', 'Expect the column standard deviation to be between a minimum value and a maximum value.', 'NUMERIC', 'Y', 'STDEV_RANGE_CHECK', 'Statistical Check', 'Provide minimum and maximum values for column standard deviation. Example: 5.0, 25.0', 'SQL', 'NUMBER, FLOAT', 'AGGREGATE'),
    (17, 'expect_column_sum_to_be_between', 'Expect the column sum to be between a minimum value and a maximum value.', 'NUMERIC', 'Y', 'SUM_RANGE_CHECK', 'Range Check', 'Provide minimum and maximum values for column sum. Example: 100, 5000', 'SQL', 'NUMBER, FLOAT', 'AGGREGATE'),
    (18, 'expect_column_value_lengths_to_be_between', 'Expect the column entries to be strings with length between a minimum value and a maximum value (inclusive).', 'VALIDITY', 'Y', 'LENGTH_CHECK', 'Length Check', 'Provide min and max string lengths. Example: 5,10', 'SQL', 'TEXT, VARCHAR, NUMBER, FLOAT', 'ROW'),
    (19, 'expect_column_values_to_match_regex', 'Expect the column entries to be strings that match a given regular expression', 'VALIDITY', 'Y', 'PATTERN_MATCH', 'Pattern Match', 'Please provide the valid regular expression which needs to be checked.      Example: Valid regex: ^d{2}-d{3}-d{3}-d{4}$ Matching Input: 91-123-456-7890', 'SQL', 'TEXT, VARCHAR', 'ROW'),
    (20, 'expect_column_values_to_not_match_regex', 'Expect the column entries to be strings that do NOT match a given regular expression', 'VALIDITY', 'Y', 'PATTERN_EXCLUSION', 'Pattern Match', 'Provide regex that column entries should NOT match. Example: ^ERR.*', 'SQL', 'TEXT, VARCHAR', 'ROW'),
    (21, 'expect_column_values_to_be_in_set', 'Expect each column value to be in a given set', 'CONFORMITY', 'Y', 'SET_INCLUSION', 'Domain Inclusion', 'Please provide the column name and the set of values expected in that column.      Optionally, include a value for "mostly" (a float between 0 and 1) if you want to allow a fraction of values not to be in the set.', 'SQL', 'TEXT, VARCHAR, NUMBER, FLOAT', 'ROW'),
    (22, 'expect_column_values_to_not_be_in_set', 'Expect column entries to not be in the set', 'VALIDITY', 'Y', 'SET_EXCLUSION', 'Domain Exclusion', 'Please provide the set of values which should not appear in the given column. Example: error,unknown', 'SQL', 'TEXT, VARCHAR, NUMBER, FLOAT', 'ROW'),
    (23, 'expect_column_unique_value_count_to_be_between', 'Expect the number of unique values to be between a minimum value and a maximum value.', 'UNIQUENESS', 'Y', 'UNIQUE_COUNT_RANGE', 'Uniqueness Distribution', 'Provide min and max count for unique values. Example: 10, 100', 'SQL', 'ALL', 'AGGREGATE'),
    (24, 'expect_column_values_to_be_unique', 'Expect each column value to be unique', 'UNIQUENESS', 'Y', 'UNIQUENESS_CHECK', 'Uniqueness Check', 'Please provide column name and optionally a value for "mostly" (float between 0 and 1) to specify the fraction of values expected to be unique.', 'SQL', 'ALL', 'ROW'),
    (25, 'unexpected_rows_expectation', 'Expectation will fail validation if the query returns one or more rows. The WHERE clause defines the fail criteria', 'SQL', 'Y', 'CUSTOM_RULE', 'Business Rule', 'Provide the full SQL query to identify failing rows.', 'SQL', NULL, 'ROW'),
    (26, 'expect_table_row_count_to_equal_source_file', 'Expect the CORE table row count to equal the source-file record count recorded in the audit-control table', 'VOLUME', 'Y', 'SOURCE_FILE_COUNT_MATCH', 'Source File Count Match', 'Optionally provide audit_control_table, sync_level, and target_table in KWARGS. Defaults to PRISM_META_PROD.META.AUDIT_CONTROL / SOURCE_TO_CORE.', 'SQL', NULL, 'TABLE');
